import{_ as i,c as n,o as s,a1 as t}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Best Practices: Effiziente Skills | Agent Skills","description":"Lernen Sie effiziente Nutzung von Agent Skills. Verbessern Sie Auslöse-Genauigkeit, reduzieren Sie Token-Verbrauch und vermeiden Sie Skill-Konflikte für bessere Performance.","frontmatter":{"title":"Best Practices: Effiziente Skills | Agent Skills","subtitle":"Best Practices","sidebarTitle":"Best Practices","description":"Lernen Sie effiziente Nutzung von Agent Skills. Verbessern Sie Auslöse-Genauigkeit, reduzieren Sie Token-Verbrauch und vermeiden Sie Skill-Konflikte für bessere Performance.","tags":["Best Practices","Performance-Optimierung","Effizienzsteigerung","KI-Verwendungstipps"],"prerequisite":["start-getting-started","start-installation"]},"headers":[],"relativePath":"de/vercel-labs/agent-skills/faq/best-practices/index.md","filePath":"de/vercel-labs/agent-skills/faq/best-practices/index.md"}'),a={name:"de/vercel-labs/agent-skills/faq/best-practices/index.md"};function r(l,e,o,u,d,h){return s(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="verwendungs-best-practices" tabindex="-1">Verwendungs-Best Practices <a class="header-anchor" href="#verwendungs-best-practices" aria-label="Permalink to &quot;Verwendungs-Best Practices&quot;">​</a></h1><h2 id="was-sie-nach-diesem-kurs-konnen" tabindex="-1">Was Sie nach diesem Kurs können <a class="header-anchor" href="#was-sie-nach-diesem-kurs-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Kurs können&quot;">​</a></h2><p>Lernen Sie nach Abschluss dieser Lektion:</p><ul><li>✅ Präzise Auswahl von Auslöse-Keywords, damit die KI Skills zum richtigen Zeitpunkt aktiviert</li><li>✅ Optimierung der Kontextverwaltung, Reduzierung des Token-Verbrauchs, Erhöhung der Reaktionsgeschwindigkeit</li><li>✅ Behandlung von Multi-Skill-Kooperationsszenarien, Vermeidung von Konflikten und Verwirrung</li><li>✅ Beherrschung häufiger Verwendungsmuster zur Steigerung der Arbeitseffizienz</li></ul><h2 id="ihre-aktuelle-herausforderung" tabindex="-1">Ihre aktuelle Herausforderung <a class="header-anchor" href="#ihre-aktuelle-herausforderung" aria-label="Permalink to &quot;Ihre aktuelle Herausforderung&quot;">​</a></h2><p>Sie sind möglicherweise auf folgende Szenarien gestoßen:</p><ul><li>✗ Eingabe &quot;帮我部署&quot;, aber die KI hat den Vercel-Deploy-Skill nicht aktiviert</li><li>✗ Ein und dieselbe Aufgabe hat mehrere Skills ausgelöst, die KI weiß nicht, welchen sie verwenden soll</li><li>✗ Skills belegen zu viel Kontext, was dazu führt, dass die KI Ihre Anforderungen &quot;vergisst&quot;</li><li>✗ Jedes Mal müssen Sie Aufgaben erneut erklären, wissen nicht, wie Sie die KI an Ihre Gewohnheiten gewöhnen können</li></ul><h2 id="wann-man-diesen-ansatz-anwendet" tabindex="-1">Wann man diesen Ansatz anwendet <a class="header-anchor" href="#wann-man-diesen-ansatz-anwendet" aria-label="Permalink to &quot;Wann man diesen Ansatz anwendet&quot;">​</a></h2><p>Wenn Sie bei der Verwendung von Agent Skills auf Probleme stoßen:</p><ul><li>🎯 <strong>Unpräzise Auslösung</strong>: Skills wurden nicht aktiviert oder der falsche Skill wurde aktiviert</li><li>💾 <strong>Kontextdruck</strong>: Skills belegen zu viele Tokens, beeinflussen andere Dialoge</li><li>🔄 <strong>Skill-Konflikte</strong>: Mehrere Skills wurden gleichzeitig aktiviert, KI-Ausführung verwirrt</li><li>⚡ <strong>Performance-Abnahme</strong>: KI-Reaktion langsam, Optimierung der Verwendung erforderlich</li></ul><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><p><strong>Designphilosophie von Agent Skills</strong>:</p><p>Agent Skills verwenden einen <strong>On-Demand-Lademechanismus</strong> – Claude lädt beim Start nur den Namen und die Beschreibung des Skills (ca. 1-2 Zeilen). Wenn relevante Keywords erkannt werden, wird der vollständige Inhalt von <code>SKILL.md</code> gelesen. Dieses Design minimiert den Kontextverbrauch und erhält die präzise Auslösung von Skills.</p><p><strong>Drei Schlüsseldimensionen der Nutzungseffizienz</strong>:</p><ol><li><strong>Auslösungspräzision</strong>: Auswahl geeigneter Auslöse-Keywords, damit Skills zum richtigen Zeitpunkt aktiviert werden</li><li><strong>Kontexteffizienz</strong>: Steuerung der Skill-Inhaltslänge, Vermeidung zu hoher Token-Nutzung</li><li><strong>Kooperationsklarheit</strong>: Klare Skill-Grenzen, Vermeidung von Multi-Skill-Konflikten</li></ol><h2 id="best-practice-1-prazise-auswahl-von-auslose-keywords" tabindex="-1">Best Practice 1: Präzise Auswahl von Auslöse-Keywords <a class="header-anchor" href="#best-practice-1-prazise-auswahl-von-auslose-keywords" aria-label="Permalink to &quot;Best Practice 1: Präzise Auswahl von Auslöse-Keywords&quot;">​</a></h2><h3 id="was-sind-auslose-keywords" tabindex="-1">Was sind Auslöse-Keywords? <a class="header-anchor" href="#was-sind-auslose-keywords" aria-label="Permalink to &quot;Was sind Auslöse-Keywords?&quot;">​</a></h3><p>Auslöse-Keywords werden im Feld <code>description</code> von <code>SKILL.md</code> definiert und geben der KI an, wann dieser Skill aktiviert werden sollte.</p><p><strong>Kernprinzip</strong>: Beschreibung soll spezifisch sein, Auslösung soll klar sein</p><h3 id="wie-schreibt-man-effektive-beschreibungen" tabindex="-1">Wie schreibt man effektive Beschreibungen? <a class="header-anchor" href="#wie-schreibt-man-effektive-beschreibungen" aria-label="Permalink to &quot;Wie schreibt man effektive Beschreibungen?&quot;">​</a></h3><h4 id="❌-falsches-beispiel-beschreibung-zu-vage" tabindex="-1">❌ Falsches Beispiel: Beschreibung zu vage <a class="header-anchor" href="#❌-falsches-beispiel-beschreibung-zu-vage" aria-label="Permalink to &quot;❌ Falsches Beispiel: Beschreibung zu vage&quot;">​</a></h4><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">my-deploy-tool</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Ein Deployment-Tool für Anwendungen</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # Zu vage, kann nicht ausgelöst werden</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span></code></pre></div><p><strong>Probleme</strong>:</p><ul><li>Keine klareren Anwendungsszenarien</li><li>Keine Keywords, die Benutzer sagen könnten</li><li>Die KI kann nicht urteilen, wann der Skill aktiviert werden soll</li></ul><h4 id="✅-richtiges-beispiel-beschreibung-spezifisch-und-beinhaltet-auslose-keywords" tabindex="-1">✅ Richtiges Beispiel: Beschreibung spezifisch und beinhaltet Auslöse-Keywords <a class="header-anchor" href="#✅-richtiges-beispiel-beschreibung-spezifisch-und-beinhaltet-auslose-keywords" aria-label="Permalink to &quot;✅ Richtiges Beispiel: Beschreibung spezifisch und beinhaltet Auslöse-Keywords&quot;">​</a></h4><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">vercel-deploy</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Deploy applications and websites to Vercel. Use this skill when user requests deployment actions such as &quot;Deploy my app&quot;, &quot;Deploy this to production&quot;, &quot;Create a preview deployment&quot;, &quot;Deploy and give me a link&quot;, or &quot;Push this live&quot;. No authentication required.</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span></code></pre></div><p><strong>Vorteile</strong>:</p><ul><li>Klare Anwendungsszenarien (Deploy applications)</li><li>Listet spezifische Auslöse-Phrasen (&quot;Deploy my app&quot;, &quot;Deploy this to production&quot;)</li><li>Beschreibt den einzigartigen Wert (No authentication required)</li></ul><h2 id="best-practice-2-kontextverwaltungstechniken" tabindex="-1">Best Practice 2: Kontextverwaltungstechniken <a class="header-anchor" href="#best-practice-2-kontextverwaltungstechniken" aria-label="Permalink to &quot;Best Practice 2: Kontextverwaltungstechniken&quot;">​</a></h2><h3 id="warum-ist-kontextverwaltung-wichtig" tabindex="-1">Warum ist Kontextverwaltung wichtig? <a class="header-anchor" href="#warum-ist-kontextverwaltung-wichtig" aria-label="Permalink to &quot;Warum ist Kontextverwaltung wichtig?&quot;">​</a></h3><p>Tokens sind eine begrenzte Ressource. Wenn die Datei <code>SKILL.md</code> zu lang ist, belegt sie viel Kontext, was dazu führt, dass die KI Ihre Anforderungen &quot;vergisst&quot; oder die Reaktion verlangsamt.</p><h3 id="kernprinzip-skill-md-kurz-halten" tabindex="-1">Kernprinzip: SKILL.md kurz halten <a class="header-anchor" href="#kernprinzip-skill-md-kurz-halten" aria-label="Permalink to &quot;Kernprinzip: SKILL.md kurz halten&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">Goldene Regel</p><p><strong>SKILL.md Datei innerhalb von 500 Zeilen halten</strong></p></div><h2 id="best-practice-3-multi-skill-kooperationsszenarien" tabindex="-1">Best Practice 3: Multi-Skill-Kooperationsszenarien <a class="header-anchor" href="#best-practice-3-multi-skill-kooperationsszenarien" aria-label="Permalink to &quot;Best Practice 3: Multi-Skill-Kooperationsszenarien&quot;">​</a></h2><h3 id="szenario-1-skill-a-und-skill-b-haben-uberlappende-auslosebedingungen" tabindex="-1">Szenario 1: Skill A und Skill B haben überlappende Auslösebedingungen <a class="header-anchor" href="#szenario-1-skill-a-und-skill-b-haben-uberlappende-auslosebedingungen" aria-label="Permalink to &quot;Szenario 1: Skill A und Skill B haben überlappende Auslösebedingungen&quot;">​</a></h3><p><strong>Problem</strong>: Sie sagen &quot;review my code&quot;, was gleichzeitig React Best Practices und Web Design Guidelines auslöst.</p><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><p><strong>Kernpunkte</strong>:</p><ol><li><strong>Auslöse-Keywords</strong>: Beschreibungen sollen spezifisch sein, verschiedene Ausdrucksformen, die Benutzer sagen könnten, beinhalten</li><li><strong>Kontextverwaltung</strong>: SKILL.md &lt; 500 Zeilen, progressive Disclosure, prioritäre Skripte</li><li><strong>Multi-Skill-Kooperation</strong>: Klares Abgrenzen von Auslöse-Keywords, klare Sequenz für Mehrfachaufgaben</li><li><strong>Performance-Optimierung</strong>: Dialog-Kontext präzisieren, Wiederholtes Laden vermeiden, Token-Nutzung überwachen</li></ol><p><strong>Best-Practices-Mantra</strong>:</p><blockquote><p>Beschreibungen sollen spezifisch sein, Auslösungen klar Dateien nicht zu lang, Skripte den Platz einnehmen Mehrere Skills abgegrenzen, Aufgabenreihenfolge klar Kontext präzise halten, regelmäßiges Bereinigen verhindert Verzögerungen</p></blockquote><hr><h2 id="anhang-quellcodereferenz" tabindex="-1">Anhang: Quellcodereferenz <a class="header-anchor" href="#anhang-quellcodereferenz" aria-label="Permalink to &quot;Anhang: Quellcodereferenz&quot;">​</a></h2><details><summary><strong>Klicken zum Anzeigen der Quellcodepositionen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-25</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilen</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>Kernprinzipien</strong>:</p><ul><li>Keep SKILL.md under 500 lines: Skill-Dateien kurz halten</li><li>Write specific descriptions: Spezifische Beschreibungen schreiben, um der KI zu helfen, zu urteilen</li><li>Use progressive disclosure: Progressive Disclosure für detaillierte Inhalte</li><li>Prefer scripts over inline code: Priorität für Skripte, um Token-Verbrauch zu reduzieren</li></ul></details>`,44)])])}const p=i(a,[["render",r]]);export{g as __pageData,p as default};
